# -*- coding: utf-8 -*-import cv2import numpy as npfrom pymycobot.mycobot import MyCobotimport timefrom GrabParams_2 import grabParamsimport rospyfrom geometry_msgs.msg import Twist# 初始化ROS节点（用于控制移动）rospy.init_node('movement', anonymous=True)# 创建发布者，发布速度控制指令到cmd_vel话题pub = rospy.Publisher('cmd_vel', Twist, queue_size=1)# 设置ROS发布频率为20Hzrate = rospy.Rate(20)# 初始化速度控制消息对象move_cmd = Twist()# 定义机械臂不同运动速度（快、正常、慢）speed_85 = 85speed_80 = 80speed_70 = 70speed_60 = 60ZB = [104.19, -18.19, 0.35, 24.25, -16.69, -49.13]ZQ = [100, -40.86, 12.12, 20.12, -10.81, -47.28]FZ=[100, -107.75, 98.52, 8.61, -6.41, -45.7]SH=[100, -122.43, 138.33, 8.7, -4.39, -45.87]# ZB = [-76.37, -18.28, 3.07, 24.96, -16.34, -49.65]  #准备# ZQ = [-80.94, -45.26, 16.25, 23.64, -13.88, -45.87]   # 抓取位置# TQ = [-88.94, 43.15, -99.93, 46.4, -2.54, -46.93]  # 抬起位置# FZ = [-84.19, 0.0, -106.78, 99.93, -7.82, -46.49]  # 放置位置# HZ = [-84.46, 63.28, -125.06, 60.11, -10.89, -47.98] #撤回# 初始化机械臂（从GrabParams配置文件读取串口和波特率）mc = MyCobot(grabParams.usb_dev, grabParams.baudrate)# 定义6种目标颜色的HSV颜色范围（用于颜色识别）lower_blue = np.array([100, 43, 46])upper_blue = np.array([124, 255, 255])lower_red = np.array([170, 120, 120])upper_red = np.array([180, 255, 255])lower_yellow = np.array([22, 93, 0])upper_yellow = np.array([34, 255, 255])lower_green = np.array([35, 80, 80])upper_green = np.array([90, 255, 255])lower_purple = np.array([120, 43, 46])upper_purple = np.array([200, 255, 255])lower_orange = np.array([11, 43, 46])upper_orange = np.array([25, 255, 255])# 运动次数计数器（控制循环执行3次）motion_num = 0# 主循环（执行3次抓取任务后退出）while True:    # 机械臂设置为红色灯（表示忙碌状态）    mc.set_color(0, 0, 255)    # 张开夹爪（255为最大张开值，速度30）    mc.set_gripper_value(255, 80)    time.sleep(0.8)  # 等待夹爪张开到位    # 机械臂移动到初始抓取准备角度（速度30）    mc.send_angles(ZB, speed_60)    time.sleep(0.6)  # 等待机械臂到位    # 初始化摄像头（设备编号2）    cap = cv2.VideoCapture(2)    # 摄像头识别循环：移动寻找目标颜色    while True:        # 设置移动速度：x方向0.02m/s（前进），z方向0（无上下移动）        move_cmd.linear.x = 0.06        move_cmd.linear.z = 0        pub.publish(move_cmd)  # 发布速度指令        # 读取摄像头帧        retval, frame = cap.read()        # 颜色识别标记：0=未找到，1=找到目标        flag = 0        # 将BGR图像转为HSV格式（HSV更适合颜色分割）        hsv = cv2.cvtColor(frame, cv2.COLOR_BGR2HSV)        # 生成各颜色的掩码（只保留目标颜色区域）        mask_blue = cv2.inRange(hsv, lower_blue, upper_blue)        mask_red = cv2.inRange(hsv, lower_red, upper_red)        mask_green = cv2.inRange(hsv, lower_green, upper_green)        mask_yellow = cv2.inRange(hsv, lower_yellow, upper_yellow)        mask_purple = cv2.inRange(hsv, lower_purple, upper_purple)        mask_orange = cv2.inRange(hsv, lower_orange, upper_orange)        # 寻找各颜色掩码的轮廓（轮廓代表目标物体形状）        contours_blue, _ = cv2.findContours(mask_blue, cv2.RETR_TREE, cv2.CHAIN_APPROX_SIMPLE)        contours_red, _ = cv2.findContours(mask_red, cv2.RETR_TREE, cv2.CHAIN_APPROX_SIMPLE)        contours_yellow, _ = cv2.findContours(mask_yellow, cv2.RETR_TREE, cv2.CHAIN_APPROX_SIMPLE)        contours_green, _ = cv2.findContours(mask_green, cv2.RETR_TREE, cv2.CHAIN_APPROX_SIMPLE)        contours_purple, _ = cv2.findContours(mask_purple, cv2.RETR_TREE, cv2.CHAIN_APPROX_SIMPLE)        contours_orange, _ = cv2.findContours(mask_orange, cv2.RETR_TREE, cv2.CHAIN_APPROX_SIMPLE)        # ---------------------- 红色目标识别 ----------------------        for contour in contours_red:            # 计算轮廓面积（过滤过小/过大的干扰区域）            area = cv2.contourArea(contour)            if 5000 < area < 15000:                # 获取轮廓的 bounding box（矩形框）                x, y, w, h = cv2.boundingRect(contour)                # 在原图上绘制矩形框（标记目标）                cv2.rectangle(frame, (x, y), (x + w, y + h), (0, 255, 0), 2)                print("红色目标坐标: x={}, y={}".format(x, y))                # 判断目标是否在摄像头视野中心区域（x:300-450, y:140-200）                if 350 < x < 480 and 180 < y < 260:                    flag = 1  # 标记找到目标        # ---------------------- 黄色目标识别 ----------------------        for contour in contours_yellow:            area = cv2.contourArea(contour)            if 5000 < area < 15000:                x, y, w, h = cv2.boundingRect(contour)                cv2.rectangle(frame, (x, y), (x + w, y + h), (0, 255, 0), 2)                print("黄色目标坐标: x={}, y={}".format(x, y))                if 350 < x < 480 and 180 < y < 280:                    flag = 1        # ---------------------- 蓝色目标识别 ----------------------        for contour in contours_blue:            area = cv2.contourArea(contour)            if 3000 < area < 20000:                x, y, w, h = cv2.boundingRect(contour)                cv2.rectangle(frame, (x, y), (x + w, y + h), (0, 255, 0), 2)                print("蓝色目标坐标: x={}, y={}".format(x, y))                if 300 < x < 450 and 190 < y < 195:                    flag = 1        # ---------------------- 绿色目标识别 ----------------------        for contour in contours_green:            area = cv2.contourArea(contour)            if 5000 < area < 20000:                x, y, w, h = cv2.boundingRect(contour)                cv2.rectangle(frame, (x, y), (x + w, y + h), (0, 255, 0), 2)                print("绿色目标坐标: x={}, y={}".format(x, y))                if 350 < x < 480 and 180 < y < 260:                    flag = 1        # ---------------------- 紫色目标识别 ----------------------        for contour in contours_purple:            area = cv2.contourArea(contour)            if 5000 < area < 15000:                x, y, w, h = cv2.boundingRect(contour)                cv2.rectangle(frame, (x, y), (x + w, y + h), (0, 255, 0), 2)                print("紫色目标坐标: x={}, y={}".format(x, y))                if 350 < x < 480 and 180 < y < 280:                    flag = 1        # ---------------------- 橙色目标识别 ----------------------        for contour in contours_orange:            area = cv2.contourArea(contour)            if 5000 < area < 15000:                x, y, w, h = cv2.boundingRect(contour)                cv2.rectangle(frame, (x, y), (x + w, y + h), (0, 255, 0), 2)                print("橙色目标坐标: x={}, y={}".format(x, y))                if 350 < x < 450 and 140 < y < 200:                    flag = 1        # 显示摄像头画面（实时查看识别结果）        cv2.imshow('frame', frame)        # 若找到目标（flag=1），退出识别循环，准备抓取        if flag == 1:            break        # 按键盘'q'键，强制退出程序        if cv2.waitKey(1) & 0xFF == ord('q'):            break    # 找到目标后，停止移动（速度设为0）    move_cmd.linear.x = 0    move_cmd.linear.z = 0    pub.publish(move_cmd)    # 释放摄像头资源，关闭图像窗口    cap.release()    cv2.destroyAllWindows()    # ---------------------- 机械臂抓取动作序列 ----------------------    # 1. 移动到抓取前准备角度（快速）    mc.send_angles(ZQ, speed_70)    time.sleep(1.2)    # 2. 闭合夹爪抓取目标（速度50，35为闭合程度）    mc.set_gripper_value(35,60)    time.sleep(1)    # 3. 抓取后抬起机械臂并收回（快速）    angle_T=mc.get_angles()    angle_T[3]=angle_T[3]+65    mc.send_angles(angle_T,speed_80)     time.sleep(0.5)    angle_T[1]= angle_T[1]-68    angle_T[2]= angle_T[2]+130    angle_T[3]=angle_T[3]-60    mc.send_angles(angle_T,85)     time.sleep(1.2)    angle_T[1]= angle_T[1]-15    mc.send_angles(angle_T,85)     time.sleep(0.2)    # 4. 移动到放置位置，张开夹爪，释放目标（快速）    mc.send_angles(FZ, speed_85)    time.sleep(1.5)    mc.set_gripper_value(100, 60)    # 5. 释放后抬起机械臂（快速）    mc.send_angles(SH,90)    time.sleep(1.2)    angle_T=mc.get_angles()    angle_T[3]=angle_T[3]+10    mc.send_angles(angle_T,80)     # 6. 回到初始待命角度（快速）    mc.send_angles(ZB, 80)    time.sleep(1.8)    # 机械臂设置为绿色灯（表示空闲状态）    mc.set_color(0, 255, 0)    # 运动次数+1，执行3次后退出主循环    motion_num += 1    if motion_num == 3:        break# ---------------------- 任务结束后，机械臂回归最终初始位置 ----------------------# 1. 调整角度（备用，原代码注释，保留结构）angle_T=mc.get_angles()angle_T[1]= angle_T[1]+30mc.send_angles(angle_T,speed_80) time.sleep(0.8)angles_final1 = [0, 0, 0, 0, 0, 0]mc.send_angles(angles_final1, 80)time.sleep(0.6)# 2. 移动到最终初始位置（速度正常）angles_final2 = [0.43, 1.93, -58.79, -28.74, -3.95, 45.26]mc.send_angles(angles_final2,80)time.sleep(1)